from pathlib import Path

# ---------- Home.tsx ----------
home = Path('/mnt/data/work/ui/src/panels/Home.tsx')
text = home.read_text()

text = text.replace(
    'const DONE_EVENT = "oddengine:calendar-done-changed";\n',
    'const DONE_EVENT = "oddengine:calendar-done-changed";\nconst TRADING_JOURNAL_KEY = "oddengine:trading:journal:v1";\nconst HOME_MONEY_EVENT = "oddengine:money-changed";\n'
)

text = text.replace(
    'async function getStorageEstimate() {\n',
    '''function unwrapGuardedData<T = any>(raw: any): T | null {\n  if (raw && typeof raw === "object" && raw.data && typeof raw.version === "string") return raw.data as T;\n  return raw as T;\n}\n\nfunction money(n: number) {\n  return Number(n || 0).toLocaleString(undefined, { style: "currency", currency: "USD", maximumFractionDigits: 0 });\n}\n\nasync function getStorageEstimate() {\n'''
)

text = text.replace(
    '  const [doneTick, setDoneTick] = useState(0);\n',
    '  const [doneTick, setDoneTick] = useState(0);\n  const [moneyTick, setMoneyTick] = useState(0);\n'
)

ent_block = '''  useEffect(() => {\n    const onEnt = () => setEntTick((x) => x + 1);\n    const onDone = () => setDoneTick((x) => x + 1);\n    try {\n      window.addEventListener(ENT_EVENT as any, onEnt);\n      window.addEventListener(DONE_EVENT as any, onDone);\n      window.addEventListener("storage", onEnt);\n    } catch {\n      // ignore\n    }\n    return () => {\n      try {\n        window.removeEventListener(ENT_EVENT as any, onEnt);\n        window.removeEventListener(DONE_EVENT as any, onDone);\n        window.removeEventListener("storage", onEnt);\n      } catch {\n        // ignore\n      }\n    };\n  }, []);\n'''
text = text.replace(ent_block, ent_block + '''\n  useEffect(() => {\n    const onMoney = () => setMoneyTick((x) => x + 1);\n    const tick = window.setInterval(onMoney, 15000);\n    try {\n      window.addEventListener(HOME_MONEY_EVENT as any, onMoney);\n      window.addEventListener("storage", onMoney);\n    } catch {\n      // ignore\n    }\n    return () => {\n      window.clearInterval(tick);\n      try {\n        window.removeEventListener(HOME_MONEY_EVENT as any, onMoney);\n        window.removeEventListener("storage", onMoney);\n      } catch {\n        // ignore\n      }\n    };\n  }, []);\n''')

apps_block = '''  const apps = useMemo(() => {\n    const all = PANEL_META.filter((p) => !["Home"].includes(normalizePanelId(p.id)));\n    const query = q.trim().toLowerCase();\n    const list = !query\n      ? all\n      : all.filter((p) => (p.title + " " + p.sub + " " + p.section).toLowerCase().includes(query));\n    return list;\n  }, [q]);\n\n'''
text = text.replace(apps_block, apps_block + '''  const moneySnapshot = useMemo(() => {\n    void moneyTick;\n    const tradingRaw = unwrapGuardedData<any>(loadJSON<any>(TRADING_JOURNAL_KEY, [] as any));\n    const tradingEntries = Array.isArray(tradingRaw) ? tradingRaw : [];\n    const tradingPnl = tradingEntries.reduce((sum: number, item: any) => sum + Number(item?.pnl || 0), 0);\n    const tradingWins = tradingEntries.filter((item: any) => Number(item?.pnl || 0) > 0).length;\n    const pokerRaw = unwrapGuardedData<any>(loadJSON<any>("oddengine:poker:v1", null as any));\n    const pokerSessions = Array.isArray(pokerRaw?.sessions) ? pokerRaw.sessions : [];\n    const pokerPnl = pokerSessions.reduce((sum: number, item: any) => sum + Number(item?.result || 0), 0);\n    const pokerCurrent = Number(pokerRaw?.bankroll?.current || 0);\n    const groceryRaw = unwrapGuardedData<any>(loadJSON<any>("oddengine:grocery:v1", null as any));\n    const groceryEstimated = Number(groceryRaw?.saverPack?.estimatedBasket || groceryRaw?.estimatedBasket || 0);\n    const groceryCouponMatches = Array.isArray(groceryRaw?.couponFeed) ? groceryRaw.couponFeed.length : 0;\n    return {\n      tradingPnl,\n      tradingCount: tradingEntries.length,\n      tradingWins,\n      pokerPnl,\n      pokerCurrent,\n      pokerCount: pokerSessions.length,\n      groceryEstimated,\n      groceryCouponMatches,\n    };\n  }, [moneyTick]);\n\n  const bestNextMove = useMemo(() => {\n    if (currentRoutine?.ev) {\n      return {\n        title: currentRoutine.mode === "active" ? "Finish the current routine step" : "Queue up the next routine step",\n        body: currentRoutine.ev.title || "Routine step",\n        cta: currentRoutine.mode === "active" ? "Open current step" : "Open next step",\n        panelId: currentRoutine.ev.panelId || "RoutineLauncher",\n        secondary: "Calendar",\n      };\n    }\n    if (moneySnapshot.tradingCount === 0) {\n      return {\n        title: "Capture your first trade note",\n        body: "Open Trading, scan a symbol, and save one setup into the journal so Home can coach from real outcomes.",\n        cta: "Open Trading",\n        panelId: "Trading",\n        secondary: "Brain",\n      };\n    }\n    if (moneySnapshot.groceryCouponMatches > 0) {\n      return {\n        title: "Turn meal plan into savings",\n        body: `You have ${moneySnapshot.groceryCouponMatches} coupon matches waiting. Build the grocery list before shopping.`,\n        cta: "Open Grocery Meals",\n        panelId: "GroceryMeals",\n        secondary: "Calendar",\n      };\n    }\n    if (!nextTrading) {\n      return {\n        title: "Schedule the next trading check-in",\n        body: "A quick premarket scan block keeps the money lane intentional instead of reactive.",\n        cta: "+ Add trading check-in",\n        panelId: "Trading",\n        secondary: "Calendar",\n      };\n    }\n    return {\n      title: "Run the operator digest",\n      body: "Use Home to pivot into the strongest move across money, routine, and family ops.",\n      cta: "Open Brain",\n      panelId: "Brain",\n      secondary: "RoutineLauncher",\n    };\n  }, [currentRoutine, moneySnapshot, nextTrading]);\n\n''')

marker = '          </div>\n\n          <div className="homeSectionTitle compact">Mission control (from Calendar)</div>\n'
replacement = '''          </div>\n\n          <div className="homeSectionTitle compact">Quick launch row</div>\n          <div className="homeQuickRow">\n            {[\n              { id: "Trading", icon: "🎯", title: "Trading", sub: "Scans, ticket, journal" },\n              { id: "Poker", icon: "♠️", title: "Poker", sub: "Bankroll + edge tracker" },\n              { id: "GroceryMeals", icon: "🛒", title: "Grocery Meals", sub: "Meal plan + savings" },\n              { id: "Books", icon: "📚", title: "Studio", sub: "Writers + artifact flow" },\n            ].map((item) => (\n              <button key={item.id} className="homeAppTile" onClick={() => onNavigate(item.id)}>\n                <div className="homeAppIcon">{item.icon}</div>\n                <div className="homeAppText">\n                  <div className="homeAppName">{item.title}</div>\n                  <div className="homeAppSub">{item.sub}</div>\n                </div>\n              </button>\n            ))}\n          </div>\n\n          <div className="homeSectionTitle compact">Best next move</div>\n          <div className="homeOpsRow homeOpsRowTwo">\n            <div className="card homeOpsCard">\n              <div className="homeOpsTop">\n                <div className="homeOpsKicker">Best next move</div>\n                <span className="badge good">⚡ Focus</span>\n              </div>\n              <div className="homeOpsTitle">{bestNextMove.title}</div>\n              <div className="homeOpsNote">{bestNextMove.body}</div>\n              <div className="row homeOpsActions">\n                <button className="tabBtn" onClick={() => {\n                  if (bestNextMove.cta === "+ Add trading check-in") addDefaultTradingCheckIn();\n                  else onNavigate(bestNextMove.panelId);\n                }}>{bestNextMove.cta}</button>\n                <button className="tabBtn" onClick={() => onNavigate(bestNextMove.secondary)}>{bestNextMove.secondary === "Brain" ? "Open Brain" : bestNextMove.secondary === "RoutineLauncher" ? "Run Routine" : "Open Calendar"}</button>\n              </div>\n            </div>\n\n            <div className="card homeOpsCard">\n              <div className="homeOpsTop">\n                <div className="homeOpsKicker">System + money snapshot</div>\n                <span className="badge warn">💸 Live</span>\n              </div>\n              <div className="homeMoneyGrid">\n                <div className="homeMoneyStat">\n                  <div className="homeMoneyLabel">Trading journal</div>\n                  <div className="homeMoneyValue">{money(moneySnapshot.tradingPnl)}</div>\n                  <div className="small">{moneySnapshot.tradingCount} notes • {moneySnapshot.tradingCount ? `${Math.round((moneySnapshot.tradingWins / moneySnapshot.tradingCount) * 100)}% wins` : "No entries yet"}</div>\n                </div>\n                <div className="homeMoneyStat">\n                  <div className="homeMoneyLabel">Poker bankroll</div>\n                  <div className="homeMoneyValue">{money(moneySnapshot.pokerCurrent)}</div>\n                  <div className="small">{money(moneySnapshot.pokerPnl)} total • {moneySnapshot.pokerCount} sessions</div>\n                </div>\n                <div className="homeMoneyStat">\n                  <div className="homeMoneyLabel">System load</div>\n                  <div className="homeMoneyValue">{runtime ? `${runtimeCpu}% / ${runtimeRam}%` : "—"}</div>\n                  <div className="small">CPU / RAM live from desktop runtime</div>\n                </div>\n                <div className="homeMoneyStat">\n                  <div className="homeMoneyLabel">Grocery saver</div>\n                  <div className="homeMoneyValue">{money(moneySnapshot.groceryEstimated)}</div>\n                  <div className="small">Estimated basket • {moneySnapshot.groceryCouponMatches} coupon matches</div>\n                </div>\n              </div>\n              <div className="row homeOpsActions">\n                <button className="tabBtn" onClick={() => onNavigate("Trading")}>Open Trading</button>\n                <button className="tabBtn" onClick={() => onNavigate("Poker")}>Open Poker</button>\n                <button className="tabBtn" onClick={() => onNavigate("GroceryMeals")}>Open Grocery</button>\n              </div>\n            </div>\n          </div>\n\n          <div className="homeSectionTitle compact">Mission control (from Calendar)</div>\n'''
if marker not in text:
    raise SystemExit('Home marker not found')
text = text.replace(marker, replacement, 1)
text = text.replace('            <CardFrame title="Recent activity" subtitle="What you touched last" storageKey="home:activity" className="softCard">',
                    '            <CardFrame title="Activity timeline" subtitle="What you touched last" storageKey="home:activity" className="softCard">')

home.write_text(text)

# ---------- Trading.tsx ----------
trading = Path('/mnt/data/work/ui/src/panels/Trading.tsx')
text = trading.read_text()

text = text.replace(
    'type ChainLoadResult = {\n  chain: PublicChainData;\n  expirations: string[];\n};\n\n',
    '''type ChainLoadResult = {\n  chain: PublicChainData;\n  expirations: string[];\n};\n\ntype TradingJournalEntry = {\n  id: string;\n  createdAt: number;\n  symbol: string;\n  setup: string;\n  bias: Input["bias"];\n  timeframe: Input["timeframe"];\n  contractLabel: string;\n  contractSymbol: string;\n  pnl: number;\n  notes: string;\n  worked: string;\n  didnt: string;\n  screenshotUrl: string;\n  score: number;\n};\n\ntype TradingAlertHook = {\n  id: string;\n  symbol: string;\n  label: string;\n  minScore: number;\n  side: "all" | "call" | "put";\n  active: boolean;\n  firedAt: number | null;\n};\n\n'''
)

text = text.replace(
    'const DEFAULTS: Input = {',
    'const JOURNAL_KEY = "oddengine:trading:journal:v1";\nconst ALERT_HOOKS_KEY = "oddengine:trading:alertHooks:v1";\nconst TRADING_EVENT = "oddengine:money-changed";\n\nconst DEFAULTS: Input = {'
)

text = text.replace(
    'function pickBest(contracts: PublicContract[], cfg: { maxAsk: number; minOi: number; targetSide: "call" | "put" | "all" }): PublicContract | null {',
    '''function safeId(prefix = "trade") {\n  return `${prefix}_${Math.random().toString(36).slice(2, 8)}_${Date.now().toString(36)}`;\n}\n\nfunction tradingMoney(n: number) {\n  return Number(n || 0).toLocaleString(undefined, { style: "currency", currency: "USD", maximumFractionDigits: 2 });\n}\n\nfunction pickBest(contracts: PublicContract[], cfg: { maxAsk: number; minOi: number; targetSide: "call" | "put" | "all" }): PublicContract | null {'''
)

text = text.replace(
    '  const [ticketTpCustomPct, setTicketTpCustomPct] = useState<number>(35);\n',
    '''  const [ticketTpCustomPct, setTicketTpCustomPct] = useState<number>(35);\n  const [journalEntries, setJournalEntries] = useState<TradingJournalEntry[]>(() => {\n    const raw = loadJSON<any>(JOURNAL_KEY, [] as any);\n    return Array.isArray(raw) ? raw as TradingJournalEntry[] : [];\n  });\n  const [journalPnl, setJournalPnl] = useState<string>("");\n  const [journalNotes, setJournalNotes] = useState<string>("");\n  const [journalWorked, setJournalWorked] = useState<string>("");\n  const [journalDidnt, setJournalDidnt] = useState<string>("");\n  const [journalScreenshot, setJournalScreenshot] = useState<string>("");\n  const [alertHooks, setAlertHooks] = useState<TradingAlertHook[]>(() => {\n    const raw = loadJSON<any>(ALERT_HOOKS_KEY, [] as any);\n    return Array.isArray(raw) ? raw as TradingAlertHook[] : [];\n  });\n'''
)

snapshot_block = '''  useEffect(() => {\n    const snapshot = loadJSON<any>("odd.trading.chainSnapshot", null);\n    const hydrated = hydrateChainFromSnapshot(snapshot);\n    if (!hydrated) return;\n    setChain((prev) => prev || hydrated);\n    if (snapshot?.expiration) setExpirations((prev) => prev.length ? prev : [snapshot.expiration]);\n    if (snapshot?.at && !lastScanAt) setLastScanAt(snapshot.at);\n  }, []);\n'''
text = text.replace(snapshot_block, snapshot_block + '''\n  useEffect(() => {\n    saveJSON(JOURNAL_KEY, journalEntries);\n    try {\n      window.dispatchEvent(new CustomEvent(TRADING_EVENT, { detail: { source: "tradingJournal", count: journalEntries.length, ts: Date.now() } }));\n    } catch {}\n  }, [journalEntries]);\n\n  useEffect(() => {\n    saveJSON(ALERT_HOOKS_KEY, alertHooks);\n  }, [alertHooks]);\n''')

selected_block = '''  useEffect(() => {\n    if (!selectedContract) return;\n    const ask = selectedContract.ask;\n    if (typeof ask === "number" && isFinite(ask)) setTicketLimit(ask);\n  }, [selectedContractKey]);\n'''
text = text.replace(selected_block, selected_block + '''\n  useEffect(() => {\n    if (!alertHooks.length) return;\n    let changed = false;\n    const inferredSide = inp.bias === "bear" ? "put" : inp.bias === "bull" ? "call" : "all";\n    const next = alertHooks.map((hook) => {\n      if (!hook.active) return hook;\n      if (hook.symbol !== inp.symbol) return hook;\n      if (hook.firedAt && Date.now() - hook.firedAt < 10 * 60 * 1000) return hook;\n      const sideOk = hook.side === "all" || hook.side === inferredSide || hook.side === inp.targetSide;\n      if (score >= hook.minScore && sideOk) {\n        changed = true;\n        pushNotif({ title: "Trading alert", body: `${hook.symbol} is back in ${score}/100 territory — ${hook.label}.`, tags: ["Trading", "Alert"], level: "success" });\n        return { ...hook, firedAt: Date.now() };\n      }\n      return hook;\n    });\n    if (changed) setAlertHooks(next);\n  }, [alertHooks, inp.symbol, inp.targetSide, inp.bias, score]);\n''')

plan_marker = '  }, [displayChain?.expirationLabel, displayChain?.sourceMode, inp, permission, score, selectedContract, tier]);\n\n'
text = text.replace(plan_marker, plan_marker + '''  const journalStats = useMemo(() => {\n    const totalPnl = journalEntries.reduce((sum, entry) => sum + Number(entry.pnl || 0), 0);\n    const wins = journalEntries.filter((entry) => Number(entry.pnl || 0) > 0).length;\n    const losses = journalEntries.filter((entry) => Number(entry.pnl || 0) < 0).length;\n    const avgPnl = journalEntries.length ? totalPnl / journalEntries.length : 0;\n    return { totalPnl, wins, losses, avgPnl, count: journalEntries.length, winRate: journalEntries.length ? Math.round((wins / journalEntries.length) * 100) : 0 };\n  }, [journalEntries]);\n\n  const addJournalEntry = () => {\n    const entry: TradingJournalEntry = {\n      id: safeId("trade"),\n      createdAt: Date.now(),\n      symbol: inp.symbol,\n      setup: inp.setup.replaceAll("_", " "),\n      bias: inp.bias,\n      timeframe: inp.timeframe,\n      contractLabel: selectedContract ? formatPublicContractLabel(selectedContract.symbol) : (displayChain?.expirationLabel || "No contract selected"),\n      contractSymbol: selectedContract?.symbol || "",\n      pnl: Number(journalPnl || 0),\n      notes: journalNotes.trim() || inp.notes.trim(),\n      worked: journalWorked.trim(),\n      didnt: journalDidnt.trim(),\n      screenshotUrl: journalScreenshot.trim(),\n      score,\n    };\n    setJournalEntries((prev) => [entry, ...prev].slice(0, 80));\n    setJournalPnl("");\n    setJournalNotes("");\n    setJournalWorked("");\n    setJournalDidnt("");\n    setJournalScreenshot("");\n    pushNotif({ title: "Trading", body: `Journal saved for ${entry.symbol}.`, tags: ["Trading", "Journal"], level: "success" });\n  };\n\n  const removeJournalEntry = (id: string) => setJournalEntries((prev) => prev.filter((entry) => entry.id !== id));\n\n  const addAlertHook = () => {\n    const inferredSide = inp.bias === "bear" ? "put" : inp.bias === "bull" ? "call" : "all";\n    const hook: TradingAlertHook = {\n      id: safeId("alert"),\n      symbol: inp.symbol,\n      label: `${inp.setup.replaceAll("_", " ")} • ${inferredSide === "all" ? "either side" : inferredSide}`,\n      minScore: Math.max(40, score),\n      side: inferredSide,\n      active: true,\n      firedAt: null,\n    };\n    setAlertHooks((prev) => [hook, ...prev].slice(0, 20));\n    pushNotif({ title: "Trading", body: `Alert hook saved for ${hook.symbol}.`, tags: ["Trading", "Alert"], level: "success" });\n  };\n\n  const toggleAlertHook = (id: string) => setAlertHooks((prev) => prev.map((hook) => hook.id === id ? { ...hook, active: !hook.active } : hook));\n  const removeAlertHook = (id: string) => setAlertHooks((prev) => prev.filter((hook) => hook.id !== id));\n\n''')

render_marker = '        <div id="trading_plan" className="card tradingLaneCard tradingLanePlan" style={{ background: "rgba(8,12,18,0.35)" }}>\n'
if render_marker not in text:
    raise SystemExit('Trading render marker not found')
text = text.replace(render_marker, '''        <div id="trading_journal" className="card tradingLaneCard tradingLanePlan" style={{ background: "rgba(8,12,18,0.35)" }}>\n          <div style={{ display: "flex", justifyContent: "space-between", gap: 12, flexWrap: "wrap", alignItems: "center" }}>\n            <div>\n              <div style={{ fontWeight: 900 }}>Execution + Journal</div>\n              <div className="small mt-1">Tie real outcomes back to your setups so the panel learns what is actually paying you.</div>\n            </div>\n            <div className="cluster wrap">\n              <span className="badge good">P/L {tradingMoney(journalStats.totalPnl)}</span>\n              <span className="badge">{journalStats.count} entries</span>\n              <span className="badge warn">{journalStats.winRate}% wins</span>\n            </div>\n          </div>\n\n          <div className="homeMoneyGrid mt-4">\n            <div className="homeMoneyStat">\n              <div className="homeMoneyLabel">Current setup</div>\n              <div className="homeMoneyValue">{inp.symbol}</div>\n              <div className="small">{inp.setup.replaceAll("_", " ")} • {inp.timeframe.toUpperCase()} • {score}/100</div>\n            </div>\n            <div className="homeMoneyStat">\n              <div className="homeMoneyLabel">Average P/L</div>\n              <div className="homeMoneyValue">{tradingMoney(journalStats.avgPnl)}</div>\n              <div className="small">Wins {journalStats.wins} • Losses {journalStats.losses}</div>\n            </div>\n          </div>\n\n          <div className="grid2 mt-4">\n            <div>\n              <label className="small">P/L</label>\n              <input className="input mt-1" value={journalPnl} onChange={(e) => setJournalPnl(e.target.value)} placeholder="25 or -12.5" />\n            </div>\n            <div>\n              <label className="small">Screenshot / chart URL</label>\n              <input className="input mt-1" value={journalScreenshot} onChange={(e) => setJournalScreenshot(e.target.value)} placeholder="Optional link to screenshot or chart" />\n            </div>\n          </div>\n          <div className="mt-4">\n            <label className="small">What worked</label>\n            <textarea rows={3} value={journalWorked} onChange={(e) => setJournalWorked(e.target.value)} placeholder="What confirmed the trade? What actually paid?" />\n          </div>\n          <div className="mt-4">\n            <label className="small">What did not work</label>\n            <textarea rows={3} value={journalDidnt} onChange={(e) => setJournalDidnt(e.target.value)} placeholder="Where did the setup slip, fake out, or become too thin?" />\n          </div>\n          <div className="mt-4">\n            <label className="small">Notes</label>\n            <textarea rows={4} value={journalNotes} onChange={(e) => setJournalNotes(e.target.value)} placeholder="Execution notes, emotions, timing, plan quality…" />\n          </div>\n\n          <div className="cluster wrap mt-4">\n            <button className="tabBtn" onClick={addJournalEntry}>Save journal entry</button>\n            <button className="tabBtn" onClick={addAlertHook}>Create alert hook</button>\n          </div>\n\n          <div className="homeTaskList mt-4">\n            {journalEntries.slice(0, 6).map((entry) => (\n              <div key={entry.id} className="homeTaskItem">\n                <div className="cluster spread">\n                  <div>\n                    <div style={{ fontWeight: 900 }}>{entry.symbol} • {entry.setup}</div>\n                    <div className="small">{new Date(entry.createdAt).toLocaleString()} • {entry.contractLabel}</div>\n                  </div>\n                  <div className={Number(entry.pnl) >= 0 ? "badge good" : "badge bad"}>{tradingMoney(entry.pnl)}</div>\n                </div>\n                {entry.worked ? <div className="small mt-2"><b>Worked:</b> {entry.worked}</div> : null}\n                {entry.didnt ? <div className="small mt-2"><b>Didn’t:</b> {entry.didnt}</div> : null}\n                {entry.notes ? <div className="small mt-2">{entry.notes}</div> : null}\n                <div className="cluster wrap mt-3">\n                  {entry.screenshotUrl ? <button className="tabBtn" onClick={() => openExternal(entry.screenshotUrl)}>Open screenshot</button> : null}\n                  <button className="tabBtn" onClick={() => removeJournalEntry(entry.id)}>Delete</button>\n                </div>\n              </div>\n            ))}\n            {!journalEntries.length ? <div className="small mt-3">No journal entries yet — save the first one right after a setup so Home can turn this into a money snapshot.</div> : null}\n          </div>\n\n          <div className="mt-5" style={{ fontWeight: 900 }}>Alert hooks</div>\n          <div className="homeTaskList mt-3">\n            {alertHooks.slice(0, 6).map((hook) => (\n              <div key={hook.id} className="homeTaskItem">\n                <div className="cluster spread">\n                  <div>\n                    <div style={{ fontWeight: 900 }}>{hook.symbol}</div>\n                    <div className="small">{hook.label} • trigger at {hook.minScore}/100</div>\n                  </div>\n                  <div className={hook.active ? "badge good" : "badge"}>{hook.active ? "Active" : "Paused"}</div>\n                </div>\n                <div className="cluster wrap mt-3">\n                  <button className="tabBtn" onClick={() => toggleAlertHook(hook.id)}>{hook.active ? "Pause" : "Resume"}</button>\n                  <button className="tabBtn" onClick={() => removeAlertHook(hook.id)}>Delete</button>\n                </div>\n              </div>\n            ))}\n            {!alertHooks.length ? <div className="small mt-3">No alert hooks yet — save one from a setup you want the scanner to call back out later.</div> : null}\n          </div>\n        </div>\n\n''' + render_marker, 1)

trading.write_text(text)

# ---------- styles ----------
styles = Path('/mnt/data/work/ui/src/styles.css')
css = styles.read_text()
css += '\n\n.homeQuickRow{ display:grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 10px; }\n@media(max-width: 1100px){ .homeQuickRow{ grid-template-columns: repeat(2, minmax(0, 1fr)); } }\n@media(max-width: 720px){ .homeQuickRow{ grid-template-columns: 1fr; } }\n.homeOpsRowTwo{ grid-template-columns: repeat(2, minmax(0, 1fr)); }\n@media(max-width: 1100px){ .homeOpsRowTwo{ grid-template-columns: 1fr; } }\n.homeMoneyGrid{ display:grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 10px; }\n@media(max-width: 760px){ .homeMoneyGrid{ grid-template-columns: 1fr; } }\n.homeMoneyStat{ border:1px solid rgba(255,255,255,0.08); background: rgba(0,0,0,0.16); border-radius: 16px; padding: 12px; }\n.homeMoneyLabel{ font-size: 11px; letter-spacing: 0.12em; text-transform: uppercase; color: rgba(240,248,255,0.62); }\n.homeMoneyValue{ font-size: 20px; font-weight: 900; margin-top: 6px; }\n.grid2{ display:grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 12px; }\n@media(max-width: 860px){ .grid2{ grid-template-columns: 1fr; } }\n'
styles.write_text(css)

# ---------- version ----------
version = Path('/mnt/data/work/ui/src/lib/version.ts')
version.write_text('// Single source of truth for the UI version label.\nexport const APP_VERSION = "10.25.2";\n')
